import { defineComponentSlotStyle } from "@yamada-ui/react"

export const nativeAccordionStyle = defineComponentSlotStyle({
  base: {
    button: {
      alignItems: "center",
      cursor: "pointer",
      display: "inline-flex",
      focusVisibleRing: "inside",
      listStyle: "none",
      px: "4",
      py: "3",
      transitionDuration: "moderate",
      transitionProperty: "common",
      w: "full",
      _disabled: { layerStyle: "disabled" },
    },
    icon: {
      color: "fg.subtle",
      fontSize: "xl",
      ml: "auto",
      transformOrigin: "center",
      transitionDuration: "moderate",
      transitionProperty: "transform",
      _groupOpen: { transform: "rotate(180deg)" },
    },
    item: { overflowAnchor: "none" },
    panel: { px: "4", _groupOpen: { pb: "3" } },
    root: { w: "full" },
  },

  props: {
    /**
     * If `true`, animate the accordion items when they are expanded or collapsed.
     *
     * @default true
     */
    animate: {
      true: {
        item: {
          _detailsContent: {
            transition: "content-visibility 0.4s allow-discrete",
          },
        },
        panel: {
          "& > div": { overflow: "hidden" },
          display: "grid",
          gridTemplateRows: "0fr",
          transitionDuration: "slow",
          transitionProperty: "grid-template-rows",
          _groupOpen: { gridTemplateRows: "1fr" },
        },
      },
    },
  },

  variants: {
    panel: {
      button: { rounded: "l2" },
      item: { layerStyle: "panel", rounded: "l2", _notFirst: { mt: "md" } },
    },
    plain: {
      item: { borderTopWidth: "1px", _last: { borderBottomWidth: "1px" } },
    },
  },

  defaultProps: {
    variant: "plain",
    animate: true,
  },
})

export type NativeAccordionStyle = typeof nativeAccordionStyle

"use client"

import type { ReactNode } from "react"
import type { HTMLProps, HTMLStyledProps, ThemeProps } from "@yamada-ui/react"
import type { NativeAccordionStyle } from "./native-accordion.style"
import type {
  UseNativeAccordionItemProps,
  UseNativeAccordionItemReturn,
  UseNativeAccordionProps,
} from "./use-native-accordion"
import { Children, cloneElement, isValidElement, useMemo } from "react"
import {
  createSlotComponent,
  styled,
  createContext,
  useSplitChildren,
} from "@yamada-ui/react"
import { ChevronDownIcon } from "../icon"
import { nativeAccordionStyle } from "./native-accordion.style"
import {
  NativeAccordionContext,
  useNativeAccordion,
  useNativeAccordionItem,
} from "./use-native-accordion"

export interface NativeAccordionItem extends NativeAccordionItemProps {}

interface ComponentContext extends Pick<
  NativeAccordionRootProps,
  "icon" | "iconHidden"
> {}

export interface NativeAccordionRootProps
  extends
    Omit<HTMLStyledProps, "onChange">,
    ThemeProps<NativeAccordionStyle>,
    UseNativeAccordionProps {
  /**
   * The accordion icon for all items to use.
   */
  icon?: ReactNode
  /**
   * If `true`, hide the accordion icon for all items.
   *
   * @default false
   */
  iconHidden?: boolean
  /**
   * If provided, generate elements based on items.
   */
  items?: NativeAccordionItem[]
}

interface ItemComponentContext
  extends
    Pick<NativeAccordionItemProps, "icon">,
    Omit<UseNativeAccordionItemReturn, "getItemProps"> {}

const [ItemComponentContext, useItemComponentContext] =
  createContext<ItemComponentContext>({
    name: "ItemComponentContext",
  })

const {
  ComponentContext,
  PropsContext: NativeAccordionPropsContext,
  useComponentContext,
  usePropsContext: useNativeAccordionPropsContext,
  withContext,
  withProvider,
} = createSlotComponent<
  NativeAccordionRootProps,
  NativeAccordionStyle,
  ComponentContext
>("native-accordion", nativeAccordionStyle)

export { NativeAccordionPropsContext, useNativeAccordionPropsContext }

/**
 * `NativeAccordion` is a component for a list that displays information in an expandable or collapsible manner using the native HTML details element.
 *
 * @see https://yamada-ui.com/docs/components/native-accordion
 */
export const NativeAccordionRoot = withProvider<
  "div",
  NativeAccordionRootProps
>(({ children, icon, iconHidden, items, ...props }) => {
  const { name, getRootProps } = useNativeAccordion(props)
  const computedChildren = useMemo(() => {
    if (children) return children

    return items?.map((props, index) => (
      <NativeAccordionItem key={index} {...props} />
    ))
  }, [children, items])
  const context = useMemo(() => ({ name }), [name])
  const componentContext = useMemo(
    () => ({ icon, iconHidden }),
    [icon, iconHidden],
  )

  return (
    <NativeAccordionContext value={context}>
      <ComponentContext value={componentContext}>
        <styled.div {...getRootProps()}>{computedChildren}</styled.div>
      </ComponentContext>
    </NativeAccordionContext>
  )
}, "root")()

export interface NativeAccordionItemProps
  extends HTMLStyledProps<"details">, UseNativeAccordionItemProps {
  /**
   * The accordion button to use.
   */
  button?: ReactNode
  /**
   * The accordion icon to use.
   */
  icon?: ReactNode
}

export const NativeAccordionItem = withContext<
  "details",
  NativeAccordionItemProps
>(({ button, children, icon, ...rest }) => {
  const {
    disabled,
    getButtonProps,
    getIconProps,
    getItemProps,
    getPanelProps,
  } = useNativeAccordionItem(rest)
  const [omittedChildren, customAccordionButton, customAccordionPanel] =
    useSplitChildren(children, NativeAccordionButton, NativeAccordionPanel)
  const context = useMemo(
    () => ({
      disabled,
      icon,
      getButtonProps,
      getIconProps,
      getPanelProps,
    }),
    [disabled, getIconProps, getPanelProps, getButtonProps, icon],
  )

  return (
    <ItemComponentContext value={context}>
      <styled.details {...getItemProps()}>
        {customAccordionButton ?? (
          <NativeAccordionButton>{button}</NativeAccordionButton>
        )}
        {customAccordionPanel ?? (
          <NativeAccordionPanel>{omittedChildren}</NativeAccordionPanel>
        )}
      </styled.details>
    </ItemComponentContext>
  )
}, "item")()

export interface NativeAccordionButtonProps extends HTMLStyledProps<"summary"> {
  /**
   * The accordion icon to use.
   */
  icon?: ReactNode
}

export const NativeAccordionButton = withContext<
  "summary",
  NativeAccordionButtonProps
>(({ children, icon: customIcon, ...rest }) => {
  const { icon: rootIcon } = useComponentContext()
  const { icon: itemIcon, getButtonProps } = useItemComponentContext()

  return (
    <styled.summary {...getButtonProps(rest)}>
      {children}

      <NativeAccordionIcon>
        {customIcon ?? itemIcon ?? rootIcon}
      </NativeAccordionIcon>
    </styled.summary>
  )
}, "button")()

export interface NativeAccordionIconProps extends HTMLStyledProps<"svg"> {}

export const NativeAccordionIcon = withContext<"svg", NativeAccordionIconProps>(
  ({ children = <ChevronDownIcon />, ...rest }) => {
    const { iconHidden } = useComponentContext()
    const { getIconProps } = useItemComponentContext()

    if (iconHidden) return null

    if (isValidElement<HTMLProps<"svg">>(children))
      return cloneElement(
        children,
        getIconProps({
          ...rest,
          ...children.props,
        }),
      )

    return Children.count(children) > 1 ? Children.only(null) : null
  },
  "icon",
)()

export interface NativeAccordionPanelProps extends HTMLStyledProps {}

export const NativeAccordionPanel = withContext<
  "div",
  NativeAccordionPanelProps
>(({ children, ...rest }) => {
  const { getPanelProps } = useItemComponentContext()

  return (
    <styled.div {...getPanelProps(rest)}>
      <styled.div>{children}</styled.div>
    </styled.div>
  )
}, "panel")()

"use client"

import type { HTMLProps, PropGetter } from "@yamada-ui/react"
import { useCallback, useId } from "react"
import {
  ariaAttr,
  createContext,
  dataAttr,
  handlerAll,
  mergeRefs,
} from "@yamada-ui/react"

interface NativeAccordionContext extends Pick<
  UseNativeAccordionReturn,
  "name"
> {}

const [NativeAccordionContext, useNativeAccordionContext] =
  createContext<NativeAccordionContext>({
    name: "NativeAccordionContext",
  })

export { NativeAccordionContext, useNativeAccordionContext }

export interface UseNativeAccordionProps extends HTMLProps {
  /**
   * If `true`, multiple accordion items can be expanded at once.
   *
   * @default false
   */
  multiple?: boolean
  /**
   * The HTML `name` attribute used for forms.
   */
  name?: string
}

export const useNativeAccordion = ({
  name,
  multiple = false,
  ...rest
}: UseNativeAccordionProps = {}) => {
  const generatedName = useId()

  const getRootProps: PropGetter = ({ ref, ...props } = {}) => ({
    ...props,
    ...rest,
    ref: mergeRefs(ref, rest.ref),
  })

  return {
    name: multiple ? undefined : (name ?? generatedName),
    getRootProps,
  }
}

export type UseNativeAccordionReturn = ReturnType<typeof useNativeAccordion>

export interface UseNativeAccordionItemProps extends HTMLProps<"details"> {
  /**
   * If `true`, the accordion item will be disabled.
   *
   * @default false
   */
  disabled?: boolean
}

export const useNativeAccordionItem = ({
  disabled,
  ...rest
}: UseNativeAccordionItemProps) => {
  const { name } = useNativeAccordionContext()

  const getItemProps: PropGetter<"details"> = ({ ref, ...props } = {}) => ({
    ref: mergeRefs(ref, rest.ref),
    name: props.name ?? rest.name ?? name,
    role: "group",
    ...rest,
    ...props,
  })

  const getButtonProps: PropGetter<"summary"> = useCallback(
    (props = {}) => ({
      "aria-disabled": ariaAttr(disabled),
      "data-disabled": dataAttr(disabled),
      ...props,
      onClick: handlerAll(props.onClick, (ev) => {
        if (!disabled) return

        ev.preventDefault()
      }),
    }),
    [disabled],
  )

  const getPanelProps: PropGetter = useCallback((props = {}) => props, [])

  const getIconProps: PropGetter<"svg"> = useCallback(
    (props = {}) => ({
      "aria-disabled": ariaAttr(disabled),
      "aria-hidden": true,
      role: "presentation",
      ...props,
    }),
    [disabled],
  )

  return {
    disabled,
    getButtonProps,
    getIconProps,
    getItemProps,
    getPanelProps,
  }
}

export type UseNativeAccordionItemReturn = ReturnType<
  typeof useNativeAccordionItem
>
